// ============================================================
// Health Monitor - Classify Health & Build Telegram Message
// ============================================================

// --- Leer resultados de nodos anteriores ---
const tokensRaw = $node['Tokens Today'].json;
const ohlcvRaw = $node['OHLCV Today'].json;
const totalsRaw = $node['Table Totals'].json;
const versionRaw = $node['Latest Version'].json;
const metadataRaw = $node['Model Metadata'].json;

// --- Detectar errores HTTP (continueOnFail pone error en .error) ---
const tokensError = $node['Tokens Today'].json?.error !== undefined;
const ohlcvError = $node['OHLCV Today'].json?.error !== undefined;
const totalsError = $node['Table Totals'].json?.error !== undefined;
const versionError = $node['Latest Version'].json?.error !== undefined;
const metadataError = $node['Model Metadata'].json?.error !== undefined;

// --- Extraer metricas ---
// exec_query devuelve un array de objetos [{cnt: N}]
let tokensToday = 'N/A';
if (!tokensError) {
  try {
    const parsed = Array.isArray(tokensRaw) ? tokensRaw : [tokensRaw];
    tokensToday = parsed[0]?.cnt ?? parsed[0]?.count ?? 'N/A';
  } catch (e) { tokensToday = 'N/A'; }
}

let ohlcvToday = 'N/A';
if (!ohlcvError) {
  try {
    const parsed = Array.isArray(ohlcvRaw) ? ohlcvRaw : [ohlcvRaw];
    ohlcvToday = parsed[0]?.cnt ?? parsed[0]?.count ?? 'N/A';
  } catch (e) { ohlcvToday = 'N/A'; }
}

// Totales por tabla
const tableMap = { tokens: 'N/A', ohlcv_data: 'N/A', features: 'N/A', labels: 'N/A', scores: 'N/A' };
if (!totalsError) {
  try {
    const rows = Array.isArray(totalsRaw) ? totalsRaw : [totalsRaw];
    for (const row of rows) {
      if (row.tabla && tableMap.hasOwnProperty(row.tabla)) {
        tableMap[row.tabla] = row.total ?? 'N/A';
      }
    }
  } catch (e) { /* mantener N/A */ }
}

// Version del modelo
let modelVersion = 'N/A';
if (!versionError) {
  try {
    // La respuesta de texto puede venir en .data, .body, o como string directo
    const raw = versionRaw.data || versionRaw.body || String(versionRaw);
    modelVersion = typeof raw === 'string' ? raw.trim() : 'N/A';
  } catch (e) { modelVersion = 'N/A'; }
}

// Metadata del modelo
let trainedAt = 'N/A';
let modelAgeDays = 'N/A';
let rfF1 = 'N/A';
let xgbF1 = 'N/A';
if (!metadataError && metadataRaw) {
  try {
    const meta = typeof metadataRaw === 'string' ? JSON.parse(metadataRaw) : metadataRaw;
    trainedAt = meta.trained_at || meta.timestamp || 'N/A';

    if (trainedAt !== 'N/A') {
      const trainDate = new Date(trainedAt);
      const now = new Date();
      modelAgeDays = Math.floor((now - trainDate) / (1000 * 60 * 60 * 24));
    }

    // Buscar metricas F1 en metadata
    if (meta.results) {
      rfF1 = meta.results.random_forest?.val_f1 ?? meta.results.random_forest?.f1 ?? 'N/A';
      xgbF1 = meta.results.xgboost?.val_f1 ?? meta.results.xgboost?.f1 ?? 'N/A';
    } else if (meta.metrics) {
      rfF1 = meta.metrics.rf_val_f1 ?? meta.metrics.rf_f1 ?? 'N/A';
      xgbF1 = meta.metrics.xgb_val_f1 ?? meta.metrics.xgb_f1 ?? 'N/A';
    }
    if (typeof rfF1 === 'number') rfF1 = rfF1.toFixed(3);
    if (typeof xgbF1 === 'number') xgbF1 = xgbF1.toFixed(3);
  } catch (e) { /* mantener N/A */ }
}

// --- Clasificar estado ---
let status = 'OK';
let emoji = '\u2705';
const warnings = [];

// Errores HTTP -> ERROR
if (tokensError && ohlcvError && totalsError) {
  status = 'ERROR';
  emoji = '\ud83d\udd34';
  warnings.push('Supabase RPC no responde');
}

// Sin datos hoy -> WARNING
if (tokensToday === 0 || tokensToday === 'N/A') {
  warnings.push('Tokens hoy: ' + tokensToday);
}
if (ohlcvToday === 0 || ohlcvToday === 'N/A') {
  warnings.push('OHLCV hoy: ' + ohlcvToday);
}

// Modelo stale -> WARNING
if (typeof modelAgeDays === 'number' && modelAgeDays > 30) {
  warnings.push('Modelo antiguo: ' + modelAgeDays + ' dias');
}
if (modelVersion === 'N/A') {
  warnings.push('Version del modelo no disponible');
}

// Ajustar status
if (status !== 'ERROR' && warnings.length > 0) {
  status = 'WARNING';
  emoji = '\u26a0\ufe0f';
}

// --- Construir mensaje HTML ---
const date = new Date().toISOString().split('T')[0];

let msg = `<b>${emoji} Health Monitor \u2014 Trading Memes</b>\n`;
msg += `<b>Fecha:</b> ${date}\n`;
msg += `<b>Estado:</b> ${emoji} ${status}\n`;
msg += '\n';

msg += '<b>\ud83d\udcca Recolecci\u00f3n Hoy:</b>\n';
msg += `\u2022 Tokens nuevos: ${tokensToday}\n`;
msg += `\u2022 OHLCV insertados: ${ohlcvToday}\n`;
msg += '\n';

msg += '<b>\ud83d\udccb Estado de Tablas:</b>\n';
msg += `\u2022 tokens: ${tableMap.tokens} filas\n`;
msg += `\u2022 ohlcv_data: ${tableMap.ohlcv_data} filas\n`;
msg += `\u2022 features: ${tableMap.features} filas\n`;
msg += `\u2022 labels: ${tableMap.labels} filas\n`;
msg += `\u2022 scores: ${tableMap.scores} filas\n`;
msg += '\n';

msg += '<b>\ud83e\udd16 Modelo:</b>\n';
msg += `\u2022 Versi\u00f3n: ${modelVersion}\n`;
msg += `\u2022 Entrenado: ${trainedAt}\n`;
msg += `\u2022 Antig\u00fcedad: ${typeof modelAgeDays === 'number' ? modelAgeDays + ' d\u00edas' : 'N/A'}\n`;
msg += `\u2022 RF F1: ${rfF1} | XGB F1: ${xgbF1}\n`;

if (warnings.length > 0) {
  msg += '\n<b>\u26a0\ufe0f Avisos:</b>\n';
  for (const w of warnings) {
    msg += `\u2022 ${w}\n`;
  }
}

return [{ json: { text: msg, chat_id: '1558705287', parse_mode: 'HTML' } }];
